// // This module decrements its value on the rising edge of the clock signal and resets to maximum when the reset signal is asserted.
module up_counter (  
    input clk,  
    input reset,  
    output reg [3:0] count  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset)  
            count <= 4'b0000;  
        else  
            count <= count + 1;  
    end  
endmodule
